Set-StrictMode -Version 2.0
function Update-GodModeLiveResult { param([string]$Project='.',[hashtable]$State=@{}) $r=Initialize-GodModeStructure $Project; $base=@{schema_version=1;updated_at=Get-GodModeIso;status='ready';headline='Aeonthra Reality Control Plane';app_url=$null;live_url=$null;arena_url=$null;browser_status='not browser-validated';latest_proof_bundle=$null;what_changed=@();what_still_failed=@();next_repair_action='Run validate-system.ps1 after edits.';validation_logs=@();proof_bundles=@();screenshots=@();console_error_count='unknown';network_failure_count='unknown';comment_mode='local-only visual notes'}; foreach($k in $State.Keys){$base[$k]=$State[$k]}; Write-GodModeJsonAtomic (Join-GodModePath $r 'live/result-state.json') $base|Out-Null; Add-GodModeJsonLine (Join-GodModePath $r 'memory/live-preview-ledger.jsonl') @{schema_version=1;created_at=Get-GodModeIso;status=$base.status;live_url=$base.live_url;arena_url=$base.arena_url}; $base }
